mapper.select:
SELECT r.relation_id, r.name, r.avatar, r.phone, r.wechat, r.email, r.relation_type, NULL AS company, r.customer_id, linked_customer.company_name AS customer_name, linked_customer.logo AS customer_logo, r.remark, r.source, r.source_customer_id, c.company_name AS source_customer_name, r.source_contact_id, r.create_user_id, r.create_time, r.update_time FROM crm_relation r LEFT JOIN crm_customer linked_customer ON r.customer_id = linked_customer.customer_id LEFT JOIN crm_customer c ON r.source_customer_id = c.customer_id WHERE r.status = 1 AND r.create_user_id = #{ownerUserId}
AND ( r.name LIKE CONCAT('%', #{query.keyword}, '%') OR COALESCE(r.phone, '') LIKE CONCAT('%', #{query.keyword}, '%') OR COALESCE(r.wechat, '') LIKE CONCAT('%', #{query.keyword}, '%') OR COALESCE(r.email, '') LIKE CONCAT('%', #{query.keyword}, '%') OR COALESCE(linked_customer.company_name, '') LIKE CONCAT('%', #{query.keyword}, '%') OR COALESCE(r.remark, '') LIKE CONCAT('%', #{query.keyword}, '%') )
AND r.relation_type = #{query.relationType}
AND r.source = #{query.source}
AND r.source_customer_id = #{query.sourceCustomerId}
AND r.customer_id = #{query.customerId}
AND r.source_contact_id = #{query.sourceContactId}
ORDER BY r.update_time DESC, r.create_time DESC
